import { Component, ElementRef, OnDestroy, Renderer2, inject } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface Candidate {
  id: string;
  name: string;
  email: string;
}

interface Chip {
  id: string;
  label: string;
  value: string;
}

const MAX_INVITES = 5;
const MAX_SUGGESTIONS = 6;

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnDestroy {
  private readonly host = inject(ElementRef<HTMLElement>);
  private readonly renderer = inject(Renderer2);
  private removeDocumentMouseDown: (() => void) | null = null;
  private nextCustomId = 1;

  readonly listboxId = 'invite-suggestions';
  readonly maxInvites = MAX_INVITES;
  readonly users: Candidate[] = [
    { id: 'ada', name: 'Ada Lovelace', email: 'ada@frontendatlas.dev' },
    { id: 'alice', name: 'Alice Johnson', email: 'alice@frontendatlas.dev' },
    { id: 'bob', name: 'Bob Smith', email: 'bob@frontendatlas.dev' },
    { id: 'charlie', name: 'Charlie Kim', email: 'charlie@frontendatlas.dev' },
    { id: 'diana', name: 'Diana Lopez', email: 'diana@frontendatlas.dev' },
    { id: 'ethan', name: 'Ethan Brown', email: 'ethan@frontendatlas.dev' },
    { id: 'fiona', name: 'Fiona Patel', email: 'fiona@frontendatlas.dev' },
    { id: 'george', name: 'George Miller', email: 'george@frontendatlas.dev' }
  ];

  chips: Chip[] = [];
  query = '';
  isOpen = false;
  activeIndex = -1;
  liveMessage = '';

  constructor() {
    this.removeDocumentMouseDown = this.renderer.listen(
      'document',
      'mousedown',
      (event: MouseEvent) => this.onDocumentMouseDown(event)
    );
  }

  get atLimit(): boolean {
    return this.chips.length >= MAX_INVITES;
  }

  get usageMessage(): string {
    return `${this.chips.length} of ${MAX_INVITES} invites used.`;
  }

  get limitMessage(): string {
    return this.atLimit
      ? 'Invite limit reached (5 of 5).'
      : this.usageMessage;
  }

  get suggestions(): Chip[] {
    const needle = this.normalize(this.query);
    if (!needle || this.atLimit) return [];

    return this.users
      .filter((user) => {
        const isSelected = this.chips.some((chip) =>
          chip.id === user.id ||
          this.normalize(chip.label) === this.normalize(user.name) ||
          this.normalize(chip.value) === this.normalize(user.email)
        );
        if (isSelected) return false;

        return this.normalize(user.name).includes(needle) ||
          this.normalize(user.email).includes(needle);
      })
      .slice(0, MAX_SUGGESTIONS)
      .map((user) => ({
        id: user.id,
        label: user.name,
        value: user.email
      }));
  }

  get activeDescendant(): string | null {
    const item = this.isOpen ? this.suggestions[this.activeIndex] : undefined;
    return item ? this.optionId(item.id) : null;
  }

  onInput(value: string): void {
    if (this.atLimit) {
      this.query = '';
      this.closeSuggestions();
      this.announceLimitGuard();
      return;
    }

    this.query = value;
    this.activeIndex = -1;
    this.syncOpenState();
  }

  onFocus(): void {
    this.syncOpenState();
  }

  handleKeyDown(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      event.preventDefault();
      this.closeSuggestions();
      return;
    }

    if (this.atLimit) {
      if (event.key === 'Enter' || event.key === ',') {
        event.preventDefault();
        this.announceLimitGuard();
      }
      return;
    }

    const items = this.suggestions;
    const count = items.length;

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      if (!count) return;
      this.isOpen = true;
      this.activeIndex = this.activeIndex < 0
        ? 0
        : (this.activeIndex + 1) % count;
      return;
    }

    if (event.key === 'ArrowUp') {
      event.preventDefault();
      if (!count) return;
      this.isOpen = true;
      this.activeIndex = this.activeIndex < 0
        ? count - 1
        : (this.activeIndex - 1 + count) % count;
      return;
    }

    if (event.key === 'Enter') {
      event.preventDefault();
      const activeSuggestion = this.isOpen
        ? items[this.activeIndex]
        : undefined;
      if (activeSuggestion) {
        this.selectSuggestion(activeSuggestion);
      } else {
        this.addCustomFromQuery();
      }
      return;
    }

    if (event.key === ',') {
      event.preventDefault();
      this.addCustomFromQuery();
      return;
    }

    if (event.key === 'Backspace' && this.query.length === 0 && this.chips.length) {
      event.preventDefault();
      this.removeChip(this.chips[this.chips.length - 1].id);
    }
  }

  onSuggestionMouseDown(event: MouseEvent, chip: Chip): void {
    event.preventDefault();
    this.selectSuggestion(chip);
  }

  selectSuggestion(chip: Chip): void {
    // A real pointer gesture can surface both mousedown and click. Once the
    // first event commits the option, the second event is intentionally a no-op.
    if (this.findDuplicate(chip)) {
      this.resetInput();
      return;
    }
    this.addChip(chip);
  }

  addCustomFromQuery(): void {
    const label = this.query.trim();
    if (!label) {
      this.resetInput();
      return;
    }

    this.addChip({
      id: 'custom-' + this.nextCustomId++,
      label,
      value: label
    });
  }

  removeChip(chipId: string): void {
    const removed = this.chips.find((chip) => chip.id === chipId);
    if (!removed) return;

    this.chips = this.chips.filter((chip) => chip.id !== chipId);
    this.liveMessage = `${removed.label} removed. ${this.usageMessage}`;
    this.syncOpenState();
  }

  optionId(candidateId: string): string {
    return 'invite-option-' + candidateId;
  }

  ngOnDestroy(): void {
    this.removeDocumentMouseDown?.();
    this.removeDocumentMouseDown = null;
  }

  private addChip(chip: Chip): void {
    const existing = this.findDuplicate(chip);
    if (existing) {
      this.liveMessage = `${existing.label} is already invited.`;
      this.resetInput();
      return;
    }

    if (this.atLimit) {
      this.announceLimitGuard();
      this.resetInput();
      return;
    }

    this.chips = [...this.chips, chip];
    this.liveMessage = `${chip.label} added. ${this.usageMessage}`;
    this.resetInput();
  }

  private findDuplicate(chip: Chip): Chip | undefined {
    const id = this.normalize(chip.id);
    const label = this.normalize(chip.label);
    const value = this.normalize(chip.value);

    return this.chips.find((item) =>
      this.normalize(item.id) === id ||
      this.normalize(item.label) === label ||
      this.normalize(item.value) === value
    );
  }

  private announceLimitGuard(): void {
    this.liveMessage = 'Invite limit reached. Remove a person to add another.';
  }

  private onDocumentMouseDown(event: MouseEvent): void {
    const target = event.target as Node | null;
    if (target && !this.host.nativeElement.contains(target)) {
      this.closeSuggestions();
    }
  }

  private syncOpenState(): void {
    this.isOpen = !this.atLimit &&
      this.normalize(this.query).length > 0 &&
      this.suggestions.length > 0;
    if (!this.isOpen) this.activeIndex = -1;
  }

  private resetInput(): void {
    this.query = '';
    this.closeSuggestions();
  }

  private closeSuggestions(): void {
    this.isOpen = false;
    this.activeIndex = -1;
  }

  private normalize(value: string): string {
    return value.trim().toLowerCase();
  }
}
